const row = $input.first().json;
const agents = row.result || [];
const overruns = agents.filter(a => Number(a.spent_today) > 1.5 * Number(a.daily_norm) && Number(a.spent_today) > 0.5);
const total_today = agents.reduce((s,a) => s + Number(a.spent_today), 0);
const total_norm = agents.reduce((s,a) => s + Number(a.daily_norm), 0);
const rep = {
  total_today: total_today.toFixed(2),
  total_norm: total_norm.toFixed(2),
  overrun_count: overruns.length,
  overruns: overruns.map(a => ({
    agent: a.agent_name,
    spent: Number(a.spent_today).toFixed(2),
    norm: Number(a.daily_norm).toFixed(2),
    ratio: (Number(a.spent_today) / Math.max(0.01, Number(a.daily_norm))).toFixed(1)
  })),
  agents_count: agents.length,
  agents_with_zero: agents.filter(a => Number(a.spent_7d) === 0).length,
  needs_alert: overruns.length > 0 || total_today > total_norm * 1.5
};
return [{ json: rep }];
